import React, { useState, useEffect } from 'react';
import {
  TextField,
  Button,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  Box,
} from '@mui/material';
import { createProductType, updateProductType } from '../services/api';

const categoryOptions = ['Asset', 'Consumable'];
const assetTypeOptions = ['Asset', 'Consumable', 'Component'];
const assetCategoryTypeOptions = ['IT', 'Non IT'];

const ProductTypeForm = ({ editing, onSave, onClose, productTypes }) => {
  const [formData, setFormData] = useState({
    display_name: '',
    api_name: '',
    display_plural_name: '',
    api_plural_name: '',
    category: '',
    parent_product_type: '',
    asset_type: '',
    asset_category_type: '',
    description: '',
  });

  useEffect(() => {
    if (editing) {
      setFormData(editing);
    } else {
      setFormData({
        display_name: '',
        api_name: '',
        display_plural_name: '',
        api_plural_name: '',
        category: '',
        parent_product_type: '',
        asset_type: '',
        asset_category_type: '',
        description: '',
      });
    }
  }, [editing]);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSave = async () => {
    try {
      if (editing) {
        await updateProductType(editing.id, formData);
      } else {
        await createProductType(formData);
      }
      onSave();
    } catch (error) {
      console.error('Error saving product type:', error);
    }
  };

  return (
    <Box component="form" sx={{ mt: 2 }}>
      <TextField
        fullWidth
        label="Display Name"
        name="display_name"
        value={formData.display_name}
        onChange={handleChange}
        margin="normal"
      />
      <TextField
        fullWidth
        label="API Name"
        name="api_name"
        value={formData.api_name}
        onChange={handleChange}
        margin="normal"
      />
      <TextField
        fullWidth
        label="Display Plural Name"
        name="display_plural_name"
        value={formData.display_plural_name}
        onChange={handleChange}
        margin="normal"
      />
      <TextField
        fullWidth
        label="API Plural Name"
        name="api_plural_name"
        value={formData.api_plural_name}
        onChange={handleChange}
        margin="normal"
      />
      <FormControl fullWidth margin="normal">
        <InputLabel>Category</InputLabel>
        <Select
          name="category"
          value={formData.category}
          onChange={handleChange}
        >
          {categoryOptions.map((option) => (
            <MenuItem key={option} value={option}>
              {option}
            </MenuItem>
          ))}
        </Select>
      </FormControl>
      <FormControl fullWidth margin="normal">
        <InputLabel>Parent Product Type</InputLabel>
        <Select
          name="parent_product_type"
          value={formData.parent_product_type}
          onChange={handleChange}
        >
          <MenuItem value="">
            <em>None</em>
          </MenuItem>
          {productTypes.map((pt) => (
            <MenuItem key={pt.id} value={pt.id}>
              {pt.display_name}
            </MenuItem>
          ))}
        </Select>
      </FormControl>
      <FormControl fullWidth margin="normal">
        <InputLabel>Asset Type</InputLabel>
        <Select
          name="asset_type"
          value={formData.asset_type}
          onChange={handleChange}
        >
          {assetTypeOptions.map((option) => (
            <MenuItem key={option} value={option}>
              {option}
            </MenuItem>
          ))}
        </Select>
      </FormControl>
      <FormControl fullWidth margin="normal">
        <InputLabel>Asset Category Type</InputLabel>
        <Select
          name="asset_category_type"
          value={formData.asset_category_type}
          onChange={handleChange}
        >
          {assetCategoryTypeOptions.map((option) => (
            <MenuItem key={option} value={option}>
              {option}
            </MenuItem>
          ))}
        </Select>
      </FormControl>
      <TextField
        fullWidth
        label="Description"
        name="description"
        value={formData.description}
        onChange={handleChange}
        margin="normal"
        multiline
        rows={4}
      />
      <Box sx={{ mt: 2, display: 'flex', justifyContent: 'space-between' }}>
        <Button variant="contained" onClick={handleSave}>
          Save
        </Button>
        <Button variant="outlined" onClick={onClose}>
          Close
        </Button>
      </Box>
    </Box>
  );
};

export default ProductTypeForm;
